use std::io::{self, Read, Write};
use std::process;

const PI: f64 = 3.1415926535;

#[derive(Debug, Clone)]
struct Parameters {
    length1: f64,
    radius1: f64,
    epsilon: f64,
    area1: f64,
    q_pts: usize,
    quads: usize,
    dist: f64,
    n_pts: usize,
    k_pts: usize,
    a_pts: usize,
    b_pts: usize,
    c_pts: usize,
    d_pts: usize,
    e_pts: usize,
    f_pts: usize,
    g_pts: usize,
    length2: f64,
    radius2: f64,
    area2: f64,
}

#[derive(Debug, Clone)]
struct Input {
    numpoints: usize,
    x: Vec<f64>,
    y: Vec<f64>,
    parameters: Parameters,
    lcm: Vec<Vec<String>>,
    pum_diag: Vec<bool>,
}

#[derive(Debug, Clone)]
struct Output {
    cmv: Vec<bool>,
    pum: Vec<Vec<bool>>,
    fuv: Vec<bool>,
    launch: bool,
}

fn realcompare(a: f64, b: f64) -> &'static str {
    let scale = a.abs().max(b.abs());
    if scale == 0.0 {
        return "EQ";
    }
    let eps = 0.5e-5 * scale;
    let diff = a - b;
    if diff > eps {
        "GT"
    } else if diff < -eps {
        "LT"
    } else {
        "EQ"
    }
}

fn distance(x1: f64, y1: f64, x2: f64, y2: f64) -> f64 {
    ((x2 - x1).powi(2) + (y2 - y1).powi(2)).sqrt()
}

fn circle_radius(p1: (f64, f64), p2: (f64, f64), p3: (f64, f64)) -> Option<f64> {
    let (x1, y1) = p1;
    let (x2, y2) = p2;
    let (x3, y3) = p3;

    let d = 2.0 * (x1 * (y2 - y3) + x2 * (y3 - y1) + x3 * (y1 - y2));
    if (d.abs() < 1e-10) {
        return None;
    }

    let ux = ((x1.powi(2) + y1.powi(2)) * (y2 - y3) + (x2.powi(2) + y2.powi(2)) * (y3 - y1) + (x3.powi(2) + y3.powi(2)) * (y1 - y2)) / d;
    let uy = ((x1.powi(2) + y1.powi(2)) * (x3 - x2) + (x2.powi(2) + y2.powi(2)) * (x1 - x3) + (x3.powi(2) + y3.powi(2)) * (x2 - x1)) / d;

    let radius = distance(ux, uy, x1, y1);
    Some(radius)
}

fn triangle_area(p1: (f64, f64), p2: (f64, f64), p3: (f64, f64)) -> f64 {
    let (x1, y1) = p1;
    let (x2, y2) = p2;
    let (x3, y3) = p3;
    0.5 * ((x2 - x1) * (y3 - y1) - (x3 - x1) * (y2 - y1)).abs()
}

fn angle_at_vertex(p1: (f64, f64), vertex: (f64, f64), p3: (f64, f64)) -> Option<f64> {
    if (p1.0 - vertex.0).abs() < 1e-10 && (p1.1 - vertex.1).abs() < 1e-10 {
        return None;
    }
    if (p3.0 - vertex.0).abs() < 1e-10 && (p3.1 - vertex.1).abs() < 1e-10 {
        return None;
    }

    let v1x = p1.0 - vertex.0;
    let v1y = p1.1 - vertex.1;
    let v2x = p3.0 - vertex.0;
    let v2y = p3.1 - vertex.1;

    let len1 = (v1x.powi(2) + v1y.powi(2)).sqrt();
    let len2 = (v2x.powi(2) + v2y.powi(2)).sqrt();

    if len1 < 1e-10 || len2 < 1e-10 {
        return None;
    }

    let dot = v1x * v2x + v1y * v2y;
    let cos_angle = (dot / (len1 * len2)).clamp(-1.0, 1.0);
    Some(cos_angle.acos())
}

fn get_quadrant(x: f64, y: f64) -> usize {
    if x > 0.0 && y >= 0.0 {
        1
    } else if x <= 0.0 && y > 0.0 {
        2
    } else if x <= 0.0 && y <= 0.0 {
        3
    } else {
        1
    }
}

fn count_quadrants(points: &[(f64, f64)]) -> usize {
    let mut quads: Vec<bool> = vec![false; 5];
    for &(x, y) in points {
        let q = get_quadrant(x, y);
        quads[q] = true;
    }
    quads.iter().filter(|&&b| b).count()
}

fn distance_to_line(ax: f64, ay: f64, bx: f64, by: f64, px: f64, py: f64) -> f64 {
    let dx = bx - ax;
    let dy = by - ay;
    let len_sq = dx * dx + dy * dy;
    if len_sq < 1e-10 {
        return distance(ax, ay, px, py);
    }
    let t = ((px - ax) * dx + (py - ay) * dy) / len_sq;
    let proj_x = ax + t * dx;
    let proj_y = ay + t * dy;
    distance(px, py, proj_x, proj_y)
}

fn evaluate_lics(input: &Input) -> Vec<bool> {
    let mut cmv = vec![false; 15];
    let n = input.numpoints;
    let pts: Vec<(f64, f64)> = (0..n).map(|i| (input.x[i], input.y[i])).collect();
    let p = &input.parameters;

    // LIC 1: Two consecutive points distance > LENGTH1
    for i in 0..n - 1 {
        if distance(pts[i].0, pts[i].1, pts[i + 1].0, pts[i + 1].1) > p.length1 {
            cmv[0] = true;
            break;
        }
    }

    // LIC 2: Three consecutive points cannot be contained in circle of radius RADIUS1
    for i in 0..n - 2 {
        if let Some(r) = circle_radius(pts[i], pts[i + 1], pts[i + 2]) {
            if r > p.radius1 {
                cmv[1] = true;
                break;
            }
        }
    }

    // LIC 3: Three consecutive points form angle < (PI - EPSILON) or > (PI + EPSILON)
    for i in 0..n - 2 {
        if let Some(angle) = angle_at_vertex(pts[i], pts[i + 1], pts[i + 2]) {
            let diff1 = (PI - p.epsilon) - angle;
            let diff2 = angle - (PI + p.epsilon);
            if realcompare(diff1, 0.0) == "GT" || realcompare(diff2, 0.0) == "LT" {
                cmv[2] = true;
                break;
            }
        }
    }

    // LIC 4: Three consecutive points form triangle with area > AREA1
    for i in 0..n - 2 {
        if triangle_area(pts[i], pts[i + 1], pts[i + 2]) > p.area1 {
            cmv[3] = true;
            break;
        }
    }

    // LIC 5: Q_PTS consecutive points lie in more than QUADS quadrants
    for i in 0..=n - p.q_pts {
        let window: Vec<(f64, f64)> = pts[i..i + p.q_pts].to_vec();
        if count_quadrants(&window) > p.quads {
            cmv[4] = true;
            break;
        }
    }

    // LIC 6: Two consecutive points with X[j] - X[i] < 0 where j = i + 1
    for i in 0..n - 1 {
        if input.x[i + 1] - input.x[i] < 0.0 {
            cmv[5] = true;
            break;
        }
    }

    // LIC 7: N_PTS consecutive points with at least one point distance > DIST from line joining first and last
    if n >= 3 {
        for i in 0..=n - p.n_pts {
            let first = pts[i];
            let last = pts[i + p.n_pts - 1];
            let mut max_dist = 0.0;
            for j in i..i + p.n_pts {
                let d = distance_to_line(first.0, first.1, last.0, last.1, pts[j].0, pts[j].1);
                if d > max_dist {
                    max_dist = d;
                }
            }
            if max_dist > p.dist {
                cmv[6] = true;
                break;
            }
        }
    }

    // LIC 8: Two points separated by K_PTS intervening points with distance > LENGTH1
    if n >= 3 {
        for i in 0..=n - 2 - p.k_pts {
            let j = i + p.k_pts + 1;
            if distance(pts[i].0, pts[i].1, pts[j].0, pts[j].1) > p.length1 {
                cmv[7] = true;
                break;
            }
        }
    }

    // LIC 9: Three points separated by A_PTS and B_PTS intervening points cannot be in circle of radius RADIUS1
    if n >= 5 {
        for i in 0..=n - 3 - p.a_pts - p.b_pts {
            let j = i + p.a_pts + 1;
            let k = j + p.b_pts + 1;
            if let Some(r) = circle_radius(pts[i], pts[j], pts[k]) {
                if r > p.radius1 {
                    cmv[8] = true;
                    break;
                }
            }
        }
    }

    // LIC 10: Three points separated by C_PTS and D_PTS intervening points form angle < (PI - EPSILON) or > (PI + EPSILON)
    if n >= 5 {
        for i in 0..=n - 3 - p.c_pts - p.d_pts {
            let j = i + p.c_pts + 1;
            let k = j + p.d_pts + 1;
            if let Some(angle) = angle_at_vertex(pts[i], pts[j], pts[k]) {
                let diff1 = (PI - p.epsilon) - angle;
                let diff2 = angle - (PI + p.epsilon);
                if realcompare(diff1, 0.0) == "GT" || realcompare(diff2, 0.0) == "LT" {
                    cmv[9] = true;
                    break;
                }
            }
        }
    }

    // LIC 11: Three points separated by E_PTS and F_PTS intervening points form triangle with area > AREA1
    if n >= 5 {
        for i in 0..=n - 3 - p.e_pts - p.f_pts {
            let j = i + p.e_pts + 1;
            let k = j + p.f_pts + 1;
            if triangle_area(pts[i], pts[j], pts[k]) > p.area1 {
                cmv[10] = true;
                break;
            }
        }
    }

    // LIC 12: Two points separated by G_PTS intervening points with X[j] - X[i] < 0
    if n >= 3 {
        for i in 0..=n - 2 - p.g_pts {
            let j = i + p.g_pts + 1;
            if input.x[j] - input.x[i] < 0.0 {
                cmv[11] = true;
                break;
            }
        }
    }

    // LIC 13: Two parts: (1) Two points separated by K_PTS intervening points with distance > LENGTH1,
    //         (2) Two points separated by K_PTS intervening points with distance < LENGTH2
    if n >= 3 {
        let part1 = (0..=n - 2 - p.k_pts).any(|i| {
            let j = i + p.k_pts + 1;
            distance(pts[i].0, pts[i].1, pts[j].0, pts[j].1) > p.length1
        });
        let part2 = (0..=n - 2 - p.k_pts).any(|i| {
            let j = i + p.k_pts + 1;
            distance(pts[i].0, pts[i].1, pts[j].0, pts[j].1) < p.length2
        });
        if part1 && part2 {
            cmv[12] = true;
        }
    }

    // LIC 14: Two parts: (1) Three points separated by A_PTS and B_PTS cannot be in circle of radius RADIUS1,
    //         (2) Three points separated by A_PTS and B_PTS can be in circle of radius RADIUS2
    if n >= 5 {
        let part1 = (0..=n - 3 - p.a_pts - p.b_pts).any(|i| {
            let j = i + p.a_pts + 1;
            let k = j + p.b_pts + 1;
            if let Some(r) = circle_radius(pts[i], pts[j], pts[k]) {
                r > p.radius1
            } else {
                false
            }
        });
        let part2 = (0..=n - 3 - p.a_pts - p.b_pts).any(|i| {
            let j = i + p.a_pts + 1;
            let k = j + p.b_pts + 1;
            if let Some(r) = circle_radius(pts[i], pts[j], pts[k]) {
                r <= p.radius2
            } else {
                false
            }
        });
        if part1 && part2 {
            cmv[13] = true;
        }
    }

    // LIC 15: Two parts: (1) Three points separated by E_PTS and F_PTS form triangle with area > AREA1,
    //         (2) Three points separated by E_PTS and F_PTS form triangle with area < AREA2
    if n >= 5 {
        let part1 = (0..=n - 3 - p.e_pts - p.f_pts).any(|i| {
            let j = i + p.e_pts + 1;
            let k = j + p.f_pts + 1;
            triangle_area(pts[i], pts[j], pts[k]) > p.area1
        });
        let part2 = (0..=n - 3 - p.e_pts - p.f_pts).any(|i| {
            let j = i + p.e_pts + 1;
            let k = j + p.f_pts + 1;
            triangle_area(pts[i], pts[j], pts[k]) < p.area2
        });
        if part1 && part2 {
            cmv[14] = true;
        }
    }

    cmv
}

fn build_pum(cmv: &[bool], lcm: &[Vec<String>], pum_diag: &[bool]) -> Vec<Vec<bool>> {
    let n = lcm.len();
    let mut pum = vec![vec![false; n]; n];

    for i in 0..n {
        for j in 0..n {
            if i == j {
                pum[i][j] = pum_diag[i];
            } else {
                match lcm[i][j].as_str() {
                    "NOTUSED" => pum[i][j] = true,
                    "ANDD" => pum[i][j] = cmv[i] && cmv[j],
                    "ORR" => pum[i][j] = cmv[i] || cmv[j],
                    _ => pum[i][j] = true,
                }
            }
        }
    }

    pum
}

fn compute_fuv(pum: &[Vec<bool>]) -> Vec<bool> {
    let n = pum.len();
    let mut fuv = vec![false; n];

    for i in 0..n {
        if !pum[i][i] {
            fuv[i] = true;
        } else {
            let all_true = pum[i].iter().all(|&v| v);
            fuv[i] = all_true;
        }
    }

    fuv
}

fn compute_launch(fuv: &[bool]) -> bool {
    fuv.iter().all(|&v| v)
}

fn parse_json_input(input_str: &str) -> Result<Input, String> {
    let trimmed = input_str.trim();
    if !trimmed.starts_with('{') {
        return Err("Input must be a JSON object".to_string());
    }
    serde_json::from_str(input_str).map_err(|e| e.to_string())
}

fn format_json_output(output: &Output) -> String {
    serde_json::to_string_pretty(output).unwrap()
}

fn main() {
    let mut input_str = String::new();
    io::stdin()
        .read_to_string(&mut input_str)
        .expect("Failed to read stdin");

    let input = match parse_json_input(&input_str) {
        Ok(i) => i,
        Err(e) => {
            eprintln!("Error parsing input: {}", e);
            process::exit(1);
        }
    };

    let cmv = evaluate_lics(&input);
    let pum = build_pum(&cmv, &input.lcm, &input.pum_diag);
    let fuv = compute_fuv(&pum);
    let launch = compute_launch(&fuv);

    let output = Output { cmv, pum, fuv, launch };
    let output_json = format_json_output(&output);

    println!("{}", output_json);
    io::stdout().flush().unwrap();
}

