fn angle_at_vertex(p1: (f64, f64), vertex: (f64, f64), p3: (f64, f64)) -> Option<f64> {
    if (p1.0 - vertex.0).abs() < 1e-10 && (p1.1 - vertex.1).abs() < 1e-10 {
        return None;
    }
    if (p3.0 - vertex.0).abs() < 1e-10 && (p3.1 - vertex.1).abs() < 1e-10 {
        return None;
    }

    let v1x = p1.0 - vertex.0;
    let v1y = p1.1 - vertex.1;
    let v2x = p3.0 - vertex.0;
    let v2y = p3.1 - vertex.1;

    let len1 = (v1x.powi(2) + v1y.powi(2)).sqrt();
    let len2 = (v2x.powi(2) + v2y.powi(2)).sqrt();

    if len1 < 1e-10 || len2 < 1e-10 {
        return None;
    }

    let dot = v1x * v2x + v1y * v2y;
    let cos_angle = (dot / (len1 * len2)).clamp(-1.0, 1.0);
    Some(cos_angle.acos())
