        for i in 0..=n - p.n_pts {
            let first = pts[i];
            let last = pts[i + p.n_pts - 1];
            let mut max_dist = 0.0;
            for j in i..i + p.n_pts {
                let d = distance_to_line(first.0, first.1, last.0, last.1, pts[j].0, pts[j].1);
                if d > max_dist {
                    max_dist = d;
                }
            }
            if max_dist > p.dist {
                cmv[6] = true;
                break;
            }
        }
    }

    // LIC 8: Two points separated by K_PTS intervening points with distance > LENGTH1
    if n >= 3 {
        for i in 0..=n - 2 - p.k_pts {
            let j = i + p.k_pts + 1;
            if distance(pts[i].0, pts[i].1, pts[j].0, pts[j].1) > p.length1 {
                cmv[7] = true;
                break;
            }
        }
    }

    // LIC 9: Three points separated by A_PTS and B_PTS intervening points cannot be in circle of radius RADIUS1
    if n >= 5 {
        for i in 0..=n - 3 - p.a_pts - p.b_pts {
            let j = i + p.a_pts + 1;
            let k = j + p.b_pts + 1;
            if let Some(r) = circle_radius(pts[i], pts[j], pts[k]) {
                if r > p.radius1 {
                    cmv[8] = true;
                    break;
                }
            }
        }
    }

    // LIC 10: Three points separated by C_PTS and D_PTS intervening points form angle < (PI - EPSILON) or > (PI + EPSILON)
    if n >= 5 {
        for i in 0..=n - 3 - p.c_pts - p.d_pts {
            let j = i + p.c_pts + 1;
            let k = j + p.d_pts + 1;
            if let Some(angle) = angle_at_vertex(pts[i], pts[j], pts[k]) {
                let diff1 = (PI - p.epsilon) - angle;
                let diff2 = angle - (PI + p.epsilon);
                if realcompare(diff1, 0.0) == "GT" || realcompare(diff2, 0.0) == "LT" {
                    cmv[9] = true;
                    break;
                }
            }
        }
    }

    // LIC 11: Three points separated by E_PTS and F_PTS intervening points form triangle with area > AREA1
    if n >= 5 {
        for i in 0..=n - 3 - p.e_pts - p.f_pts {
            let j = i + p.e_pts + 1;
            let k = j + p.f_pts + 1;
            if triangle_area(pts[i], pts[j], pts[k]) > p.area1 {
                cmv[10] = true;
                break;
            }
        }
    }

    // LIC 12: Two points separated by G_PTS intervening points with X[j] - X[i] < 0
    if n >= 3 {
        for i in 0..=n - 2 - p.g_pts {
            let j = i + p.g_pts + 1;
            if input.x[j] - input.x[i] < 0.0 {
                cmv[11] = true;
                break;
            }
        }
    }

    // LIC 13: Two parts: (1) Two points separated by K_PTS intervening points with distance > LENGTH1,
    //         (2) Two points separated by K_PTS intervening points with distance < LENGTH2
    if n >= 3 {
        let part1 = (0..=n - 2 - p.k_pts).any(|i| {
            let j = i + p.k_pts + 1;
            distance(pts[i].0, pts[i].1, pts[j].0, pts[j].1) > p.length1
        });
        let part2 = (0..=n - 2 - p.k_pts).any(|i| {
            let j = i + p.k_pts + 1;
            distance(pts[i].0, pts[i].1, pts[j].0, pts[j].1) < p.length2
        });
        if part1 && part2 {
            cmv[12] = true;
        }
    }

    // LIC 14: Two parts: (1) Three points separated by A_PTS and B_PTS cannot be in circle of radius RADIUS1,
    //         (2) Three points separated by A_PTS and B_PTS can be in circle of radius RADIUS2
    if n >= 5 {
        let part1 = (0..=n - 3 - p.a_pts - p.b_pts).any(|i| {
            let j = i + p.a_pts + 1;
            let k = j + p.b_pts + 1;
            if let Some(r) = circle_radius(pts[i], pts[j], pts[k]) {
                r > p.radius1
            } else {
                false
            }
        });
        let part2 = (0..=n - 3 - p.a_pts - p.b_pts).any(|i| {
            let j = i + p.a_pts + 1;
            let k = j + p.b_pts + 1;
            if let Some(r) = circle_radius(pts[i], pts[j], pts[k]) {
                r <= p.radius2
            } else {
                false
            }
        });
        if part1 && part2 {
            cmv[13] = true;
        }
    }

    // LIC 15: Two parts: (1) Three points separated by E_PTS and F_PTS form triangle with area > AREA1,
    //         (2) Three points separated by E_PTS and F_PTS form triangle with area < AREA2
    if n >= 5 {
        let part1 = (0..=n - 3 - p.e_pts - p.f_pts).any(|i| {
            let j = i + p.e_pts + 1;
            let k = j + p.f_pts + 1;
            triangle_area(pts[i], pts[j], pts[k]) > p.area1
        });
        let part2 = (0..=n - 3 - p.e_pts - p.f_pts).any(|i| {
            let j = i + p.e_pts + 1;
            let k = j + p.f_pts + 1;
            triangle_area(pts[i], pts[j], pts[k]) < p.area2
        });
        if part1 && part2 {
            cmv[14] = true;
        }
    }

    cmv
}

fn build_pum(cmv: &[bool], lcm: &[Vec<String>], pum_diag: &[bool]) -> Vec<Vec<bool>> {
    let n = lcm.len();
    let mut pum = vec![vec![false; n]; n];

    for i in 0..n {
        for j in 0..n {
            if i == j {
                pum[i][j] = pum_diag[i];
            } else {
                match lcm[i][j].as_str() {
                    "NOTUSED" => pum[i][j] = true,
                    "ANDD" => pum[i][j] = cmv[i] && cmv[j],
                    "ORR" => pum[i][j] = cmv[i] || cmv[j],
                    _ => pum[i][j] = true,
                }
            }
        }
    }

    pum
}

fn compute_fuv(pum: &[Vec<bool>]) -> Vec<bool> {
    let n = pum.len();
    let mut fuv = vec![false; n];

    for i in 0..n {
        if !pum[i][i] {
            fuv[i] = true;
        } else {
            let all_true = pum[i].iter().all(|&v| v);
            fuv[i] = all_true;
        }
    }

    fuv
}

fn compute_launch(fuv: &[bool]) -> bool {
    fuv.iter().all(|&v| v)
}

fn parse_json_input(input_str: &str) -> Result<Input, String> {
    let trimmed = input_str.trim();
    if !trimmed.starts_with('{') {
        return Err("Input must be a JSON object".to_string());
    }
    serde_json::from_str(input_str).map_err(|e| e.to_string())
}

fn format_json_output(output: &Output) -> String {
    serde_json::to_string_pretty(output).unwrap()
}

fn main() {
    let mut input_str = String::new();
    io::stdin()
        .read_to_string(&mut input_str)
        .expect("Failed to read stdin");

    let input = match parse_json_input(&input_str) {
        Ok(i) => i,
        Err(e) => {
            eprintln!("Error parsing input: {}", e);
            process::exit(1);
        }
    };

    let cmv = evaluate_lics(&input);
    let pum = build_pum(&cmv, &input.lcm, &input.pum_diag);
    let fuv = compute_fuv(&pum);
    let launch = compute_launch(&fuv);

    let output = Output {
        cmv,
        pum,
        fuv,
        launch,
    };
    let output_json = format_json_output(&output);

    println!("{}", output_json);
    io::stdout().flush().unwrap();
}
